function asText(value) {
  if (value == null) return '';
  if (typeof value === 'string') return value;
  if (Array.isArray(value)) return value.map(asText).filter(Boolean).join(' ');
  if (typeof value === 'object') {
    if (typeof value.text === 'string') return value.text;
    if (typeof value.value === 'string') return value.value;
  }
  return String(value);
}

function compactSpaces(value) {
  return asText(value).replace(/\r/g, '').replace(/[ \t]+/g, ' ').replace(/\n{3,}/g, '\n\n').trim();
}

function decodeHtml(value) {
  return asText(value)
    .replace(/<br\s*\/?>/gi, '\n')
    .replace(/<\/p>/gi, '\n')
    .replace(/<\/div>/gi, '\n')
    .replace(/<[^>]+>/g, ' ')
    .replace(/&nbsp;/gi, ' ')
    .replace(/&amp;/gi, '&')
    .replace(/&lt;/gi, '<')
    .replace(/&gt;/gi, '>');
}

function matchFirst(text, patterns) {
  for (const pattern of patterns) {
    const match = text.match(pattern);
    if (match?.[1]) return compactSpaces(match[1]);
  }
  return null;
}

function parsePtBrDateTime(value) {
  const text = compactSpaces(value);
  if (!text) return null;

  const normalized = text
    .replace(/às?/gi, ' ')
    .replace(/hs?/gi, '')
    .replace(/h(?![a-z])/gi, ':')
    .replace(/\s+/g, ' ')
    .trim();

  const match = normalized.match(/(\d{1,2})\/(\d{1,2})\/(\d{4})(?:\s+(\d{1,2})(?::(\d{2}))?)?/);
  if (!match) return null;

  const day = match[1].padStart(2, '0');
  const month = match[2].padStart(2, '0');
  const year = match[3];
  const hour = (match[4] ?? '00').padStart(2, '0');
  const minute = (match[5] ?? '00').padStart(2, '0');
  return `${year}-${month}-${day}T${hour}:${minute}:00-03:00`;
}

function inferSource(input) {
  const explicit = compactSpaces(input.source).toLowerCase();
  if (explicit) return explicit;

  const joined = [
    input.mailbox,
    input.from,
    input.to,
    input.subject,
    input.body_text,
    input.body_html,
  ].map((part) => asText(part).toLowerCase()).join(' ');

  if (joined.includes('contato@certifast.com.br')) return 'certifast';
  if (joined.includes('contato@certiid.com.br')) return 'certiid';
  if (joined.includes('certisign')) return 'certifast';
  if (joined.includes('certifast')) return 'certifast';
  if (joined.includes('certiid') || joined.includes('ar certi id')) return 'certiid';
  return 'unknown';
}

function inferEventType(input) {
  const explicit = compactSpaces(input?.parsed?.event_type).toLowerCase();
  if (explicit.includes('cancel')) return 'cancelamento';
  if (explicit.includes('reag')) return 'reagendamento';
  if (explicit.includes('novo')) return 'novo_agendamento';

  const joined = [input.subject, input.body_text, input.body_html].map((part) => asText(part).toLowerCase()).join(' ');
  if (joined.includes('cancelado') || joined.includes('cancelamento') || joined.includes('agendamento cancelado')) return 'cancelamento';
  if (joined.includes('reagend')) return 'reagendamento';
  if (joined.includes('novo pedido agendado') || joined.includes('novo agendamento realizado') || joined.includes('novo agendamento')) return 'novo_agendamento';
  return 'unknown';
}

function extractCertifast(input) {
  const content = compactSpaces(`${input.subject || ''}\n${input.body_text || ''}\n${decodeHtml(input.body_html || '')}`);
  const date = matchFirst(content, [/Data:\s*(.+)/i]);
  const hour = matchFirst(content, [/Hora:\s*(.+)/i]);

  return {
    customer_name: matchFirst(content, [/Cliente:\s*(.+)/i]),
    customer_document: matchFirst(content, [/(?:CPF\/CNPJ|CNPJ\/CPF):\s*(.+)/i]),
    customer_phone: matchFirst(content, [/Telefone(?:\s*Celular)?:\s*(.+)/i]),
    customer_email: matchFirst(content, [/Email:\s*([^\s]+@[^\s]+)/i]),
    pedido_numero: matchFirst(content, [/Pedido:\s*(.+)/i, /pedido código\s*(\d+)/i]),
    protocolo_numero: matchFirst(content, [/Código:\s*(.+)/i]),
    product_name: matchFirst(content, [/Produto:\s*(.+)/i]),
    location_name: matchFirst(content, [/Posto:\s*(.+)/i]),
    data_agendada: parsePtBrDateTime(date && hour ? `${date} ${hour}` : input.subject),
    observacoes: compactSpaces([
      matchFirst(content, [/Produto:\s*(.+)/i]),
      matchFirst(content, [/Posto:\s*(.+)/i]),
    ].filter(Boolean).join(' | ')) || null,
  };
}

function extractCertiid(input) {
  const content = compactSpaces(`${decodeHtml(input.body_html || '')}\n${input.body_text || ''}`);
  const dateTimeRaw = matchFirst(content, [
    /Data e horário\s*:??\s*(.+?)\s*(?:Nome completo|CNPJ \/ CPF|Telefone|E-mail|$)/i,
    /Data e horário\s*(.+)/i,
  ]);

  return {
    pedido_numero: matchFirst(content, [/Pedido\s*:??\s*(.+?)\s*(?:Produto|Data e horário|Nome completo|$)/i]),
    product_name: matchFirst(content, [/Produto\s*:??\s*(.+?)\s*(?:Data e horário|Nome completo|CNPJ \/ CPF|Telefone|E-mail|$)/i]),
    customer_name: matchFirst(content, [/Nome completo\s*:??\s*(.+?)\s*(?:CNPJ \/ CPF|Telefone|E-mail|$)/i]),
    customer_document: matchFirst(content, [/CNPJ \/ CPF\s*:??\s*(.+?)\s*(?:Telefone|E-mail|$)/i]),
    customer_phone: matchFirst(content, [/Telefone\s*:??\s*(.+?)\s*(?:E-mail|$)/i]),
    customer_email: matchFirst(content, [/E-mail\s*:??\s*([^\s]+@[^\s]+)/i]),
    data_agendada: parsePtBrDateTime(dateTimeRaw),
    observacoes: compactSpaces([
      matchFirst(content, [/Produto\s*:??\s*(.+?)\s*(?:Data e horário|Nome completo|CNPJ \/ CPF|Telefone|E-mail|$)/i]),
    ].filter(Boolean).join(' | ')) || null,
  };
}

const raw = $json;
const normalized = {
  source: raw.source ?? null,
  mailbox: raw.mailbox ?? raw.to?.value?.[0]?.address ?? raw.to ?? null,
  from: raw.from?.value?.[0]?.address ?? raw.from?.text ?? raw.from ?? raw.sender ?? null,
  to: raw.to?.value?.[0]?.address ?? raw.to?.text ?? raw.to ?? null,
  subject: raw.subject ?? raw.headers?.subject ?? null,
  body_text: compactSpaces(raw.body_text ?? raw.textPlain ?? raw.text ?? raw.plainText ?? raw.body ?? ''),
  body_html: raw.body_html ?? raw.textHtml ?? raw.html ?? '',
  message_id: raw.message_id ?? raw.messageId ?? raw.headers?.['message-id'] ?? raw.headers?.messageId ?? null,
  external_id: raw.external_id ?? raw.uid ?? raw.id ?? raw.messageId ?? null,
  received_at: raw.received_at ?? raw.date ?? raw.sentDate ?? new Date().toISOString(),
  parsed: raw.parsed ?? null,
  raw,
};

const source = inferSource(normalized);
const extracted = source === 'certiid' ? extractCertiid(normalized) : extractCertifast(normalized);
const eventType = inferEventType(normalized);

return [{
  json: {
    source,
    mailbox: normalized.mailbox,
    from: normalized.from,
    to: normalized.to,
    subject: normalized.subject,
    body_text: normalized.body_text,
    body_html: normalized.body_html,
    message_id: normalized.message_id,
    external_id: normalized.external_id,
    received_at: normalized.received_at,
    parsed: {
      event_type: normalized?.parsed?.event_type ?? eventType,
      customer_name: normalized?.parsed?.customer_name ?? extracted.customer_name ?? null,
      customer_email: normalized?.parsed?.customer_email ?? extracted.customer_email ?? null,
      customer_phone: normalized?.parsed?.customer_phone ?? extracted.customer_phone ?? null,
      customer_document: normalized?.parsed?.customer_document ?? extracted.customer_document ?? null,
      protocolo_numero: normalized?.parsed?.protocolo_numero ?? extracted.protocolo_numero ?? null,
      pedido_numero: normalized?.parsed?.pedido_numero ?? extracted.pedido_numero ?? null,
      data_agendada: normalized?.parsed?.data_agendada ?? extracted.data_agendada ?? null,
      observacoes: normalized?.parsed?.observacoes ?? extracted.observacoes ?? null,
      product_name: normalized?.parsed?.product_name ?? extracted.product_name ?? null,
      location_name: normalized?.parsed?.location_name ?? extracted.location_name ?? null,
      source_sender: normalized.from,
    },
    raw,
  }
}];
